KEEP.initModeToggle=()=>{KEEP.utils.modeToggle={themeModeToggleBtn:document.querySelector(".tool-dark-light-toggle"),iconDom:document.querySelector(".tool-dark-light-toggle i"),enableLightMode(){document.body.classList.remove("dark-mode"),document.body.classList.add("light-mode"),this.iconDom.className="fas fa-moon",KEEP.styleStatus.isDark=!1,KEEP.setStyleStatus()},enableDarkMode(){document.body.classList.add("dark-mode"),document.body.classList.remove("light-mode"),this.iconDom.className="fas fa-sun",KEEP.styleStatus.isDark=!0,KEEP.setStyleStatus()},isDarkPrefersColorScheme(){return window.matchMedia&&window.matchMedia("(prefers-color-scheme: dark)")},initModeStatus(){var e=KEEP.getStyleStatus();e?e.isDark?this.enableDarkMode():this.enableLightMode():this.isDarkPrefersColorScheme().matches?this.enableDarkMode():this.enableLightMode()},initModeToggleButton(){this.themeModeToggleBtn.addEventListener("click",()=>{document.body.classList.contains("dark-mode")?this.enableLightMode():this.enableDarkMode()})},initModeAutoTrigger(){const e=this.isDarkPrefersColorScheme();e.addEventListener("change",e=>{e.matches?this.enableDarkMode():this.enableLightMode()})}},KEEP.utils.modeToggle.initModeStatus(),KEEP.utils.modeToggle.initModeToggleButton(),KEEP.utils.modeToggle.initModeAutoTrigger()};